const items = $input.all();
let ollamaStatus = 'error';
let qdrantStatus = 'error';
try { if (items[0] && items[0].json && items[0].json.models) ollamaStatus = 'ok'; } catch(e) {}
try { if (items[1] && items[1].json && items[1].json.status === 'ok') qdrantStatus = 'ok'; } catch(e) {}
return [{ json: { ollama: ollamaStatus, qdrant: qdrantStatus, n8n: 'ok' } }];

// Normalise the document list from doc-server into the API shape
// the frontend expects.
const raw = $input.first().json;

// doc-server returns an array directly
const list = Array.isArray(raw) ? raw : [];

const docs = list.map(d => ({
  id:         d.id,
  filename:   d.filename,
  type:       (d.mime_type || '').includes('pdf')  ? 'pdf'
            : (d.mime_type || '').includes('word') ? 'docx'
            : (d.mime_type || '').includes('sheet') || (d.mime_type || '').includes('xlsx') ? 'xlsx'
            : 'document',
  chunks:     d.chunks  || 0,
  date:       d.uploaded_at || new Date().toISOString(),
  status:     d.status  || 'processing',
  fileSize:   d.file_size || 0,
  collection: d.collection || '',
  indexedAt:  d.indexed_at || null,
  error:      d.error_message || null,
}));

return [{ json: docs }];

const body = $input.first().json.body || $input.first().json;
const message   = body.message   || '';
const sessionId = body.sessionId || 'default';
if (!message.trim()) throw new Error('Empty message');
return [{ json: { message, sessionId } }];

// Build context from both Vector and Keyword search results
const message = $('Parse Input').first().json.message;

let allHits = [];

// Consolidate hits from all input items
for (const item of $input.all()) {
    // Vector Search (Qdrant)
    if (item.json.result && Array.isArray(item.json.result)) {
        allHits = allHits.concat(item.json.result.map(h => ({
            text: h.payload?.text,
            filename: h.payload?.filename,
            score: h.score,
            source: 'vector'
        })));
    }
    // Keyword Search (Custom Search API)
    if (item.json.results && Array.isArray(item.json.results)) {
        allHits = allHits.concat(item.json.results.map(h => ({
            text: h.excerpt || h.text || '',
            filename: h.filename,
            score: h.score,
            source: 'keyword'
        })));
    }
}

// Filter out invalid hits and remove duplicates by text
const hits = allHits.filter((hit, index, self) => 
    hit.text && index === self.findIndex((t) => t.text === hit.text)
).slice(0, 5); // Limit to top 5 combined results

let context = '';
const sources = [];

if (hits.length > 0) {
    context = hits.map((h, i) => {
        const fn = h.filename || 'unknown';
        const txt = h.text.replace(/\s+/g, ' ');
        sources.push({ 
            file: fn, 
            excerpt: txt.slice(0, 200), 
            score: Math.round((h.score || 0) * 100),
            type: h.source 
        });
        return `[Source ${i+1}: ${fn} (${h.source})]
${txt}`;
    }).join('\n\n---\n\n');
}

const systemPrompt = context
    ? `You are a smart and helpful AI assistant for Riga City Council.
Your goal is to provide accurate, well-structured, and helpful answers based on the provided context.

INSTRUCTIONS:
1.  **Analyze**: Read the user's question and the provided context carefully.
2.  **Think**: In your response, first include a <thinking> section where you break down the user's request and plan your answer step-by-step.
3.  **Answer**: Provide a clear, concise, and helpful answer based ONLY on the provided context. If the answer is not in the context, say you don't know based on the documents.
4.  **Language**: Always answer in the same language as the user's question.

Context:
${context}`
    : `You are a smart and helpful AI assistant for Riga City Council.
The user asked a question, but no relevant documents were found in the knowledge base.

INSTRUCTIONS:
1.  **Acknowledge**: Inform the user that you couldn't find specific documents related to their query in the local knowledge base.
2.  **General Knowledge**: You may provide a general answer based on your broad training data, but clearly state that it's NOT from the official documents.
3.  **Suggest**: Suggest they rephrase or check the official Riga.lv website if applicable.

User Question: ${message}`;

return {
    prompt: systemPrompt,
    sources: sources
};

const ollamaResp = $input.first().json;
const answer  = ollamaResp.message?.content || 'Sorry, I could not generate a response.';
const sources = $('Build RAG Prompt').first().json.sources || [];
return [{ json: { answer, sources, executionId: $execution.id } }];

// Extract and validate upload payload
const body = $input.first().json.body || $input.first().json;
const { filename, fileBase64, mimeType } = body;

if (!filename || !fileBase64) {
  throw new Error('Missing filename or fileBase64 in request body');
}

return [{ json: { filename, fileBase64, mimeType: mimeType || 'application/octet-stream' } }];

// Chunk the extracted text and obtain embeddings from Ollama
// Then prepare Qdrant point objects for batch insertion

const { extractedText, id, collection, filename, textLength } = $input.first().json;

if (!extractedText || extractedText.trim().length < 10) {
  // No text – mark as ready with 0 chunks and skip embedding
  return [{ json: { docId: id, collection, totalChunks: 0, points: [], noText: true } }];
}

const CHUNK_SIZE = 500;
const OVERLAP    = 50;
const EMBED_MODEL = 'nomic-embed-text-v2-moe';
const OLLAMA_URL  = 'http://host.docker.internal:11434/api/embeddings';

// ── Chunk text ──────────────────────────────────────────────────────────────
const chunks = [];
for (let pos = 0; pos < extractedText.length; pos += (CHUNK_SIZE - OVERLAP)) {
  const text = extractedText.slice(pos, pos + CHUNK_SIZE).trim();
  if (text.length >= 20) chunks.push(text);
}

// Cap at 200 chunks to avoid n8n timeouts on huge documents
const cappedChunks = chunks.slice(0, 200);

// ── Generate embeddings ──────────────────────────────────────────────────────
const points = [];
for (let i = 0; i < cappedChunks.length; i++) {
  try {
    const resp = await fetch(OLLAMA_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: EMBED_MODEL, prompt: cappedChunks[i] }),
    });
    const data = await resp.json();
    if (data.embedding && data.embedding.length > 0) {
      points.push({
        id: Date.now() + i,   // unique numeric ID required by Qdrant
        vector: data.embedding,
        payload: {
          text:        cappedChunks[i],
          doc_id:      id,
          filename:    filename,
          chunk_index: i,
        },
      });
    }
  } catch (err) {
    console.error(`[chunk ${i}] embedding error: ${err.message}`);
  }
}

return [{ json: { docId: id, collection, totalChunks: cappedChunks.length, points } }];

// Only insert if we have embedding points to add
const { points, docId, collection, totalChunks, noText } = $input.first().json;

if (noText || !points || points.length === 0) {
  return [{ json: { docId, collection, totalChunks: 0, inserted: 0, skip: true } }];
}

return [{ json: { docId, collection, totalChunks, points, inserted: points.length } }];

const body = $input.first().json.body || $input.first().json;
const { query, docId, limit } = body;
if (!query || query.trim().length === 0) throw new Error('query is required');
return [{ json: { query: query.trim(), docId: docId || null, limit: limit || 10 } }];

const body = $input.first().json.body || $input.first().json;
const id = body.id;
if (!id) throw new Error('id is required');
return [{ json: { id } }];

const result = $input.first().json;
const collection = result.collection;

// If deletion failed, pass through error
if (result.error) {
  return [{ json: { ok: false, error: result.error } }];
}

return [{ json: { ok: true, collection } }];
